ALTER TABLE "DIRKSPZM32"."LVS_LGR_ORT" ADD CONSTRAINT "CHECK_LGR_ORT_REG_HOEHE_FW" CHECK (STRAT_REGAL_HOEHE_FW in (-STRAT_ORT_ABSTAND_FAKTOR,0,STRAT_ORT_ABSTAND_FAKTOR)) ENABLE;
